INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (24001, 30000, 0, 1, 2, 15, 0, "", 35, "", 0);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (91002, 40000, 0, 100, 8, 1, 0, "", 36, "", 0);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (91002, 40001, 1, 150, 8, 1, 0, "今日は記念日、お祝いですね！\n焼肉、お寿司、ピザ、ケーキ～☆\nあなたとパーティできるなんて、\n幸せです～♪", 37, "ぺコリーヌ", 107501);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (91002, 40001, 1, 150, 8, 2, 0, "この記念日を迎えられたのは、\n主さまの器量の賜物\nさすがは主さまでございます\nえらい、えらい♪", 38, "コッコロ", 107601);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (91002, 40001, 1, 150, 8, 3, 0, "あんたもけっこうやるじゃない！\nちょっとは…割と…け、けっこう\n見直しちゃったわ\n褒めてあげる♪", 39, "キャル", 107801);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (91002, 40001, 1, 150, 8, 4, 0, "あなたと私にとって、\n今日は特別な日\nあなたの支えがあるから、\n私は頑張れるんです！", 40, "スズメ", 107701);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (91002, 40001, 1, 150, 8, 5, 0, "今日はキミにとっての\n特別な記念日だにゃ\nキミの活躍にはいつも\n猫ながら感謝してるにゃ～♪", 41, "タマキ", 107901);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (91002, 40001, 2, 150, 8, 6, 0, "う～かき氷食べ過ぎて、\n身体が冷えちゃいました…\nあなたの体温で温めてください！\nギューーッ♪", 42, "ぺコリーヌ", 107501);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (91002, 40001, 2, 150, 8, 7, 0, "夏は危険がいっぱいと申します…\nですが、わたくしが主さまを\nしっかりとお守りいたしますよ", 43, "コッコロ", 107601);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (91002, 40001, 2, 150, 8, 8, 0, "ん～なんであんたと、ひと夏を\n過ごすことになったのかな…\n結構楽しいからいいけど！\nさ、まだまだ遊ぶわよ！", 44, "キャル", 107801);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (91002, 40001, 2, 150, 8, 9, 0, "あなたと過ごすはじめての夏…\nいまからドキドキが止まりません\n楽しくて素敵な思い出が、\nまた一つ増えるんですね♪", 45, "スズメ", 107701);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (91002, 40001, 2, 150, 8, 10, 0, "夏は一番の稼ぎ時にゃのに、\n今年はキミと過ごしたいって\n思ってるにゃ楽しい思い出\n増やしてくれるかにゃ？", 46, "タマキ", 107901);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (91002, 40003, 0, 150, 8, 1, 0, "", 57, "", 0);
