INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (23001, 20001, 0, 20, 2, 10, 0, "", 320, "", 0);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (24001, 40011, 1, 1, 2, 1, 0, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", 321, "リリ", 125801);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (24001, 40011, 1, 1, 2, 2, 0, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", 322, "クリア", 126001);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (24001, 40011, 1, 1, 2, 3, 0, "んーと。\nこれ、あげる。\nはい", 323, "プレシア", 126101);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (24001, 40011, 2, 1, 2, 4, 0, "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", 324, "リリ", 125801);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (24001, 40011, 2, 1, 2, 5, 0, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", 325, "クリア", 126001);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (24001, 40011, 2, 1, 2, 6, 0, "お兄。\nきてくれて、うれしい", 326, "プレシア", 126101);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (91002, 80009, 0, 100, 8, 1, 532001, "", 327, "", 0);
